package dev.harrison.rendacomcarro.finance.web;import jakarta.validation.constraints.*;import java.math.BigDecimal;import java.time.LocalDate;import org.springframework.format.annotation.DateTimeFormat;public class PaymentForm {@NotNull@DateTimeFormat(iso=DateTimeFormat.ISO.DATE)private LocalDate date=LocalDate.now();@NotNull@DecimalMin("0.00")private BigDecimal principal=BigDecimal.ZERO;@NotNull@DecimalMin("0.00")private BigDecimal interest=BigDecimal.ZERO;@NotNull@DecimalMin("0.00")private BigDecimal extra=BigDecimal.ZERO;private String externalReference;private String notes;public LocalDate getDate(){return date;}public void setDate(LocalDate v){date=v;}public BigDecimal getPrincipal(){return principal;}public void setPrincipal(BigDecimal v){principal=v;}public BigDecimal getInterest(){return interest;}public void setInterest(BigDecimal v){interest=v;}public BigDecimal getExtra(){return extra;}public void setExtra(BigDecimal v){extra=v;}public String getExternalReference(){return externalReference;}public void setExternalReference(String v){externalReference=v;}public String getNotes(){return notes;}public void setNotes(String v){notes=v;}}
